public static long solve(long n) {
    long candidate = n + 1;
    while (true) {
        if (isPalindrome(candidate) && checkDigitFrequency(candidate)) {
            return candidate;
        }
        candidate++;
    }
}

private static boolean isPalindrome(long x) {
    String s = Long.toString(x);
    int left = 0;
    int right = s.length() - 1;
    while (left < right) {
        if (s.charAt(left) != s.charAt(right)) {
            return false;
        }
        left++;
        right--;
    }
    return true;
}

private static boolean checkDigitFrequency(long candidate) {
    String s = Long.toString(candidate);
    int[] freq = new int[10];
    for (char c : s.toCharArray()) {
        int digit = c - '0';
        freq[digit]++;
    }
    if (freq[0] > 0) {
        return false;
    }
    for (int i = 1; i <= 9; i++) {
        if (freq[i] != 0 && freq[i] != i) {
            return false;
        }
    }
    return true;
}
