                            if (candNum > n && candNum < bestCandidate) {
                                bestCandidate = candNum;
                            }
                        } catch (NumberFormatException e) {
                        }
                    }
                } else {
                    List<Character> leftPrefix = new ArrayList<>();
                    for (int digit : digitSet) {
                        int count = (digit == centerDigit) ? (digit - 1) / 2 : digit / 2;
                        for (int j = 0; j < count; j++) {
                            leftPrefix.add((char)('0' + digit));
                        }
                    }
                    Collections.sort(leftPrefix);
                    StringBuilder leftPrefixBuilder = new StringBuilder();
                    for (char c : leftPrefix) {
                        leftPrefixBuilder.append(c);
                    }
                    String center = String.valueOf((char)('0' + centerDigit));
                    String fullPalindrome = leftPrefixBuilder.toString() + center + new StringBuilder(leftPrefixBuilder.toString()).reverse().toString();
                    if (L > nLen) {
