import java.util.*;

public class SpecialNumbers {
    public static long solve(long n) {
        TreeSet<Long> candidates = new TreeSet<>();
        for (int bit = 0; bit < (1 << 9); bit++) {
            Set<Integer> set = new HashSet<>();
            int totalLength = 0;
            for (int i = 0; i < 9; i++) {
                if ((bit & (1 << i)) != 0) {
                    int digit = i + 1;
                    set.add(digit);
                    totalLength += digit;
                }
            }
            if (set.isEmpty()) 
                continue;

            int oddCount = 0;
            int centerDigit = -1;
            for (int d : set) {
                if (d % 2 == 1) {
                    oddCount++;
                    centerDigit = d;
                }
            }
            if (oddCount > 1) 
                continue;

            int halfLength = (totalLength - (centerDigit != -1 ? 1 : 0)) / 2;
            int[] counts = new int[10];
            for (int d : set) {
                counts[d] = d;
            }
            if (centerDigit != -1) {
                counts[centerDigit]--;
            }
            for (int d = 1; d <= 9; d++) {
                counts[d] /= 2;
            }

            StringBuilder part1 = new StringBuilder();
            for (int d = 1; d <= 9; d++) {
                for (int j = 0; j < counts[d]; j++) {
                    part1.append((char)('0' + d));
                }
            }
            if (part1.length() != halfLength) {
                continue;
            }

            String centerStr = (centerDigit != -1) ? String.valueOf(centerDigit) : "";
            String part1Str = part1.toString();
            String part2Str = new StringBuilder(part1Str).reverse().toString();
            String candidateStr = part1Str + centerStr + part2Str;
            try {
                long candidateNum = Long.parseLong(candidateStr);
                candidates.add(candidateNum);
            } catch (NumberFormatException e) {
                continue;
            }
        }

        Long res = candidates.higher(n);
        if (res == null) 
            return -1;
        return res;
    }
}
